const sourceItem = $input.first()?.json ?? {};
const triggerSource = sourceItem.triggerSource ?? 'manual';
const triggerLabel = sourceItem.triggerLabel ?? 'Manual run';
return [
  { json: { name: 'homepage', url: 'https://gimenez.dev/', expectJsonStatus: false, triggerSource, triggerLabel } },
  { json: { name: 'health_api', url: 'https://gimenez.dev/api/health', expectJsonStatus: true, triggerSource, triggerLabel } },
  { json: { name: 'war_room', url: 'https://gimenez.dev/war-room', expectJsonStatus: false, triggerSource, triggerLabel } },
  { json: { name: 'war_room_data', url: 'https://gimenez.dev/api/war-room/data', expectJsonStatus: false, triggerSource, triggerLabel } }
];

const checkedAt = new Date().toISOString();
const workflowStaticData = $getWorkflowStaticData('global');
const inputs = $input.all();
const triggerSource = inputs[0]?.json?.triggerSource ?? 'scheduled';
const triggerLabel = inputs[0]?.json?.triggerLabel ?? (triggerSource === 'manual' ? 'Manual run' : 'Scheduled run');
const targets = [
  { name: 'homepage', url: 'https://gimenez.dev/', expectJsonStatus: false },
  { name: 'health_api', url: 'https://gimenez.dev/api/health', expectJsonStatus: true },
  { name: 'war_room', url: 'https://gimenez.dev/war-room', expectJsonStatus: false },
  { name: 'war_room_data', url: 'https://gimenez.dev/api/war-room/data', expectJsonStatus: false }
];

const results = inputs.map((item) => {
  const targetIndex = item.pairedItem?.item ?? 0;
  const target = targets[targetIndex] || targets[0];
  const bodyText = String(item.json.body || '');
  let appStatus = null;

  if (target.expectJsonStatus) {
    try {
      const parsed = JSON.parse(bodyText);
      appStatus = parsed.status ?? null;
    } catch (error) {
      appStatus = bodyText ? 'invalid-json' : null;
    }
  }

  const healthy = !item.json.error
    && Number(item.json.statusCode || 0) >= 200
    && Number(item.json.statusCode || 0) < 400
    && (!target.expectJsonStatus || appStatus === 'healthy');

  return {
    name: target.name,
    url: target.url,
    healthy,
    statusCode: item.json.statusCode ?? null,
    statusMessage: item.json.statusMessage ?? null,
    appStatus,
    error: item.json.error ?? null,
    bodyPreview: bodyText.slice(0, 160)
  };
});

const failures = results.filter((result) => !result.healthy);
const previousFailures = Number(workflowStaticData.consecutiveFailures || 0);
const consecutiveFailures = failures.length > 0 ? previousFailures + 1 : 0;
const shouldEscalate = failures.length > 0 && consecutiveFailures >= 2;

workflowStaticData.lastCheckedAt = checkedAt;
workflowStaticData.lastSummary = failures.length > 0 ? failures.map((failure) => failure.name).join(', ') : 'healthy';
workflowStaticData.consecutiveFailures = consecutiveFailures;
workflowStaticData.lastStatus = failures.length > 0 ? 'degraded' : 'healthy';

return [
  {
    json: {
      workflow: 'site-sentinel',
      checkedAt,
      triggerSource,
      triggerLabel,
      status: failures.length > 0 ? (shouldEscalate ? 'incident' : 'degraded') : 'healthy',
      shouldEscalate,
      consecutiveFailures,
      summary: failures.length > 0
        ? `${failures.length} failing checks: ${failures.map((failure) => failure.name).join(', ')}`
        : 'all checks healthy',
      results
    }
  }
];

const payload = $input.first().json;
const drillMode = $env.CONTROL_PLANE_DRILL === '1';
const shouldNotify = drillMode || payload.triggerSource === 'manual' || payload.status !== 'healthy';
const failingChecks = (payload.results || []).filter((result) => !result.healthy).map((result) => result.name);
const icon = payload.status === 'healthy'
  ? ':white_check_mark:'
  : payload.status === 'degraded'
    ? ':warning:'
    : ':rotating_light:';
const lines = [
  `${icon} *Site Sentinel* ${String(payload.status || 'unknown').toUpperCase()}`,
  `Run: ${payload.triggerLabel || payload.triggerSource || 'manual'}`,
  `Checked: ${payload.checkedAt}`,
  `Summary: ${payload.summary}`
];
if (drillMode) {
  lines.push('Mode: control-plane drill');
}
if (failingChecks.length > 0) {
  lines.push(`Failing checks: ${failingChecks.join(', ')}`);
}
return [
  {
    json: {
      ...payload,
      slackNotification: {
        skip: !shouldNotify,
        channel: 'C0ALX8C12TG',
        text: lines.join('\n')
      }
    }
  }
];

const payload = $input.first().json;

if (!payload.shouldEscalate) {
  return [{ json: payload }];
}

throw new Error(JSON.stringify({
  workflow: payload.workflow,
  checkedAt: payload.checkedAt,
  consecutiveFailures: payload.consecutiveFailures,
  summary: payload.summary,
  failingChecks: payload.results.filter((result) => !result.healthy)
}));
